import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";
  const query = "English Premier League winner";
  const category = "sports";

  const discovery = await callMcpSkill({
    toolId,
    toolName: "search_and_get_outcomes",
    args: { query, category }
  });

  const eventTitle = typeof discovery?.eventTitle === "string" ? discovery.eventTitle : "";
  const eventSlug = typeof discovery?.eventSlug === "string" ? discovery.eventSlug : "";
  const outcomes = Array.isArray(discovery?.outcomes) ? discovery.outcomes : [];

  const ranked = pickTopSemanticCandidates({
    target: "exact English Premier League winner market",
    candidates: outcomes.map((outcome) => ({
      ...outcome,
      eventTitle,
      eventSlug
    })),
    requiredTerms: ["English Premier League", "winner"],
    avoidTerms: ["premier league top scorer", "relegation", "manager", "player", "match"],
    limit: 3
  });

  const bestCandidate = Array.isArray(ranked) && ranked.length > 0 ? ranked[0] : null;
  const bestName = bestCandidate && typeof bestCandidate.name === "string" ? bestCandidate.name : "";
  const bestConditionId = bestCandidate && typeof bestCandidate.conditionId === "string" ? bestCandidate.conditionId : "";
  const bestTokenId = bestCandidate && typeof bestCandidate.tokenId === "string" ? bestCandidate.tokenId : "";

  const exactEventMatch =
    String(eventTitle).toLowerCase().includes("english premier league") &&
    String(eventTitle).toLowerCase().includes("winner");

  const exactOutcomeMatch =
    bestName.toLowerCase() === "english premier league winner" ||
    bestName.toLowerCase().includes("english premier league winner");

  if (!exactEventMatch || !bestCandidate || (!bestConditionId && !bestTokenId) || !exactOutcomeMatch) {
    return {
      query,
      exactMatch: false,
      matchedEventTitle: eventTitle || null,
      matchedEventSlug: eventSlug || null,
      selectedOutcome: bestName || null,
      reason: "Discovery did not confirm the exact matched English Premier League winner market, so analysis was stopped early.",
      shortlistCount: Array.isArray(outcomes) ? outcomes.length : 0
    };
  }

  const liquidity = await callMcpSkill({
    toolId,
    toolName: "analyze_event_outcome_liquidity",
    args: {
      slug: eventSlug,
      outcomes: [bestName],
      limit: 1,
      sortBy: "volume"
    }
  });

